-- Sinopsis de todos los libros
-- Ejecutar en phpMyAdmin: selecciona biblioteca → pestaña SQL → pega y ejecuta

UPDATE libros SET descripcion = 'Un joven huérfano descubre en su undécimo cumpleaños que es un mago y es admitido en el Colegio Hogwarts de Magia y Hechicería, donde aprenderá el oficio mientras hace amigos y enemigos, y descubre la verdad sobre la misteriosa muerte de sus padres.' WHERE titulo = 'Harry Potter y la piedra filosofal';

UPDATE libros SET descripcion = 'En una sociedad totalitaria bajo la vigilancia del Gran Hermano, Winston Smith trabaja para el Partido reescribiendo la historia. Cuando se enamora de Julia y contacta con la resistencia, descubre que la rebelión tiene un precio devastador.' WHERE titulo = '1984';

UPDATE libros SET descripcion = 'La saga de la familia Buendía a lo largo de siete generaciones en el pueblo ficticio de Macondo. Una obra cumbre del realismo mágico latinoamericano que mezcla lo cotidiano con lo fantástico en una historia de amor, guerra y soledad.' WHERE titulo = 'Cien años de soledad';

UPDATE libros SET descripcion = 'Bilbo Bolsón, un hobbit que lleva una vida tranquila, es arrastrado por el mago Gandalf y una compañía de enanos en una aventura épica para recuperar el tesoro custodiado por el dragón Smaug bajo la Montaña Solitaria.' WHERE titulo = 'El Hobbit';

UPDATE libros SET descripcion = 'Las aventuras del ingenioso hidalgo Don Quijote de la Mancha y su fiel escudero Sancho Panza recorriendo España en busca de aventuras caballerescas. Considerada la primera novela moderna y una de las obras más importantes de la literatura universal.' WHERE titulo = 'Don Quijote de la Mancha';

UPDATE libros SET descripcion = 'Geronimo Stilton es un ratón periodista de Ratonia que vive aventuras increíbles alrededor del mundo junto a su familia. Una serie de libros infantiles llena de humor, misterio y amistad.' WHERE titulo = 'Geronimo Stilton';

UPDATE libros SET descripcion = 'En un futuro lejano, el planeta desértico Arrakis es el único lugar donde se produce la especia más valiosa del universo. Paul Atreides se ve envuelto en una guerra de poder y traiciones que lo convertirá en el líder de los Fremen.' WHERE titulo = 'Dune';

UPDATE libros SET descripcion = 'En una sociedad futura donde los bomberos no apagan fuegos sino que queman libros, Guy Montag empieza a cuestionar el sistema cuando conoce a una joven que le hace redescubrir el valor de la lectura y el pensamiento libre.' WHERE titulo = 'Fahrenheit 451';

UPDATE libros SET descripcion = 'En un futuro postapocalíptico, Katniss Everdeen es seleccionada para participar en los Juegos del Hambre, un brutal reality show televisado donde jóvenes de los distritos luchan a muerte para entretenimiento de la Capital.' WHERE titulo = 'Los juegos del hambre';

UPDATE libros SET descripcion = 'En la Inglaterra del siglo XIX, las cinco hijas Bennet deben encontrar marido para asegurar su futuro económico. Elizabeth Bennet y el orgulloso Mr. Darcy protagonizan uno de los romances más célebres de la literatura inglesa.' WHERE titulo = 'Orgullo y prejuicio';

UPDATE libros SET descripcion = 'El Conde Drácula, un noble vampiro de Transilvania, viaja a Inglaterra con la ayuda del abogado Jonathan Harker. Un grupo de valientes deberá enfrentarse a él para salvar a la joven Mina de su influencia sobrenatural.' WHERE titulo = 'Drácula';

UPDATE libros SET descripcion = 'El héroe griego Odiseo intenta regresar a casa tras la caída de Troya. Su viaje de diez años está plagado de obstáculos: monstruos, dioses enfadados, la hechicera Circe y las sirenas que intentan desviarlo de su camino.' WHERE titulo = 'La Odisea';

UPDATE libros SET descripcion = 'El profesor Robert Langdon es llamado al Museo del Louvre tras el asesinato de su director. Las pistas dejadas en el cuerpo le llevan a descubrir un secreto que la Iglesia ha protegido durante siglos y que podría cambiar el mundo.' WHERE titulo = 'El código Da Vinci';

UPDATE libros SET descripcion = 'En Alabama durante los años 30, el abogado Atticus Finch defiende a un hombre negro acusado injustamente de violar a una mujer blanca. Vista a través de los ojos de su hija Scout, es una poderosa historia sobre la justicia y el racismo.' WHERE titulo = 'Matar a un ruiseñor';

UPDATE libros SET descripcion = 'En el pueblo de Derry, siete niños se enfrentan a una entidad maligna que se disfraza de payaso llamado Pennywise. Veintisiete años después, ya adultos, deberán regresar para cumplir una promesa y acabar con el mal de una vez por todas.' WHERE titulo = 'It';

UPDATE libros SET descripcion = 'En una granja, los animales se rebelan contra el granjero humano para crear una sociedad igualitaria. Pero poco a poco los cerdos se van convirtiendo en lo mismo que querían derrocar. Una sátira política sobre el totalitarismo.' WHERE titulo = 'Rebelión en la granja';

UPDATE libros SET descripcion = 'Kvothe, el mago más temido de su época, narra su propia historia desde su infancia como hijo de actores ambulantes hasta convertirse en estudiante en la Universidad y después en leyenda. Una épica historia de magia, música y venganza.' WHERE titulo = 'El nombre del viento';

UPDATE libros SET descripcion = 'Rachel Watson, una mujer que viaja en tren cada día y observa a una pareja perfecta desde la ventanilla, se ve envuelta en la desaparición de esa mujer. Un thriller psicológico de múltiples narradores con un giro final impactante.' WHERE titulo = 'La chica del tren';

UPDATE libros SET descripcion = 'Una breve historia de la humanidad desde los primeros humanos hasta el siglo XXI. Yuval Noah Harari analiza cómo nuestra especie dominó el planeta gracias a la capacidad única de creer en cosas imaginadas como el dinero, los dioses y los derechos humanos.' WHERE titulo = 'Sapiens';
